changeSet.sql:
DROP FUNCTION IF EXISTS nextval;
//
CREATE FUNCTION nextval (seq_name varchar(100))
RETURNS bigint
BEGIN
DECLARE cur_val bigint;
SELECT
cur_value INTO cur_val
FROM
sequence
WHERE
name = seq_name;
IF cur_val IS NOT NULL THEN
UPDATE
sequence
SET
cur_value = IF (
(cur_value + increment) > max_value OR (cur_value + increment) < min_value,
IF (
cycle = TRUE,
IF (
(cur_value + increment) > max_value,
min_value,
max_value
),
NULL
),
cur_value + increment
)
WHERE
name = seq_name;
END IF;
RETURN cur_val;
END
//

          DROP FUNCTION IF EXISTS nextvalcreditnote;
          //
          CREATE FUNCTION nextvalcreditnote (seq_name varchar(100))
          RETURNS varchar(2000)
          BEGIN
          DECLARE cur_val bigint;
         	DECLARE cur_valuestr varchar(2000);
          DECLARE append varchar(360);
          DECLARE cur_year INT;
			SET cur_year = (SELECT YEAR(CURRENT_DATE()));
          SELECT
              cur_value INTO cur_val
          FROM
              sequence
          WHERE
              name = seq_name;
          IF cur_val IS NOT NULL THEN
          UPDATE
              sequence
          SET
          cur_value = IF (
          (cur_value + increment) > max_value OR (cur_value + increment) < min_value,
          IF (
          cycle = TRUE,
          IF (
          (cur_value + increment) > max_value,
          min_value,
          max_value
          ),
          NULL
          ),
          cur_value + increment
          )
          WHERE
              name = seq_name;
          SET append = (SELECT YEAR(CURRENT_DATE()));
          SET cur_valuestr = (SELECT LPAD(cur_val, 7, "0"));
          END IF;
          RETURN CONCAT('CN',cur_year,'-',cur_valuestr);
          END
          //

          DROP FUNCTION IF EXISTS nextvalpayment;
          //
          CREATE FUNCTION nextvalpayment (seq_name varchar(100))
              RETURNS varchar(2000)
          BEGIN
          DECLARE cur_val bigint;
         	DECLARE cur_valuestr varchar(2000);
          DECLARE append varchar(360);
          DECLARE cur_year INT;
			SET cur_year = (SELECT YEAR(CURRENT_DATE()));
          SELECT
              cur_value INTO cur_val
          FROM
              sequence
          WHERE
              name = seq_name;
          IF cur_val IS NOT NULL THEN
          UPDATE
              sequence
          SET
              cur_value = IF (
                              (cur_value + increment) > max_value OR (cur_value + increment) < min_value,
                              IF (
                                          cycle = TRUE,
                                          IF (
                                                      (cur_value + increment) > max_value,
                                                      min_value,
                                                      max_value
                                              ),
                                          NULL
                                  ),
                              cur_value + increment
                  )
          WHERE
              name = seq_name;
          SET append = (SELECT YEAR(CURRENT_DATE()));
          SET cur_valuestr = (SELECT LPAD(cur_val, 7, "0"));
          END IF;
          RETURN CONCAT('PY',cur_year,'-',cur_valuestr);
          END
          //

