changeSet.sql:
         CREATE PROCEDURE IF NOT EXISTS updates_mvnoid(IN old_mvnoid INT, IN new_mvnoid INT)
         BEGIN
 DECLARE tableName VARCHAR(100);
 DECLARE done BOOLEAN DEFAULT FALSE;

 DECLARE cur CURSOR FOR
         SELECT TABLE_NAME
         FROM INFORMATION_SCHEMA.COLUMNS
         WHERE TABLE_SCHEMA = 'adoptconvergebss'
           AND COLUMN_NAME LIKE '%mvnoid%'
           AND TABLE_NAME NOT IN (
                                  'tblmmvno', 'tblmhierarchy', 'tbltteamhierarchymapping', 'tblstaffuser',
                                  'tblroles', 'tblstaffrolerel', 'tblstaffbusinessunitrel',
                                  'tblmstaffledgerdetails', 'tblstaffservicearearel',
                                  'tbltstaffledgertransactionmapping', 'tbltstaffuserreceiptmapping',
                                  'tblmdebitdocassignstaffmapping', 'tblmticketassignstaffmapping',
                                  'tblworkflowassignstaffmapping','tblclientservice'
             );

 DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
	SET FOREIGN_KEY_CHECKS = 0;

     OPEN cur;
     read_loop: LOOP
     FETCH cur INTO tableName;
     IF done THEN
         LEAVE read_loop;
     END IF;
     SET @sql = CONCAT('UPDATE ', tableName, ' SET mvnoId =',new_mvnoid,' WHERE mvnoId = ', old_mvnoid ,';');
     select @sql;
     PREPARE stmt FROM @sql;
     EXECUTE stmt;
     DEALLOCATE PREPARE stmt;
     END LOOP;
     CLOSE cur;
     SET FOREIGN_KEY_CHECKS = 1;

     END//

