CREATE FUNCTION adoptconvergebss.nextvalconnection(dummy VARCHAR(50))
RETURNS VARCHAR(50)
DETERMINISTIC
BEGIN
    DECLARE last_number INT DEFAULT 0;
    DECLARE new_number INT DEFAULT 0;
    DECLARE padded VARCHAR(10);
    DECLARE conn_no VARCHAR(50);

    SELECT
        CAST(SUBSTRING_INDEX(connection_no, '-', -1) AS UNSIGNED)
    INTO last_number
    FROM adoptconvergebss.tbltcustomerservicemapping
    WHERE connection_no LIKE CONCAT('SERV', YEAR(CURDATE()), '-%')
    ORDER BY custid DESC
    LIMIT 1;

    SET new_number = COALESCE(last_number, 0) + 1;

    SET padded = LPAD(new_number, 7, '0');

    SET conn_no = CONCAT('SERV', YEAR(CURDATE()), '-', padded);

    RETURN conn_no;
END;


CREATE FUNCTION adoptconvergebss.nextvalconnection(seq_key_in VARCHAR(100))
RETURNS VARCHAR(50)
DETERMINISTIC
BEGIN
    DECLARE seq_key VARCHAR(150);
    DECLARE new_no INT DEFAULT 0;
    DECLARE padded VARCHAR(10);
    DECLARE conn_no VARCHAR(50);

    SET seq_key = CONCAT(seq_key_in, '_', YEAR(CURDATE()));

    INSERT INTO connection_sequence (key_name, last_number)
    VALUES (seq_key, 1)
    ON DUPLICATE KEY UPDATE last_number = last_number + 1;

    SELECT last_number INTO new_no
    FROM connection_sequence
    WHERE key_name = seq_key;

    SET padded = LPAD(new_no, 7, '0');
    SET conn_no = CONCAT('SERV', YEAR(CURDATE()), '-', padded);

    RETURN conn_no;
END;
